const lead = $('DB: Load Full Lead').item.json;
const callLog = $('DB: Load Latest Call Log').item.json[0] || {};
let score = 0;
const reasons = [];

// Budget (0–30)
const b = (lead.budget || '').toLowerCase();
if (b.includes('100k') || b.includes('100,000')) { score += 30; reasons.push('Budget 100k+'); }
else if (b.includes('50k') || b.includes('50,000')) { score += 22; reasons.push('Budget 50k+'); }
else if (b.includes('25k')) { score += 15; reasons.push('Budget 25k+'); }
else if (b.includes('10k')) { score += 8;  reasons.push('Budget 10k+'); }
else if (b.includes('5k'))  { score += 4;  reasons.push('Budget 5k+'); }

// Urgency (0–25)
const u = (lead.urgency || '').toLowerCase();
if (u === 'high' || u.includes('asap') || u.includes('urgent')) { score += 25; reasons.push('High urgency'); }
else if (u === 'medium' || u.includes('soon')) { score += 15; reasons.push('Medium urgency'); }
else if (u === 'low' || u.includes('quarter')) { score += 5; reasons.push('Low urgency'); }

// Business Size (0–20)
const bz = (lead.business_size || '').toLowerCase();
if (bz.includes('enterprise') || bz.includes('500+')) { score += 20; reasons.push('Enterprise'); }
else if (bz.includes('mid') || bz.includes('100') || bz.includes('50')) { score += 12; reasons.push('Mid-market'); }
else if (bz.includes('small') || bz.includes('startup')) { score += 6; reasons.push('SMB'); }

// Engagement (0–15)
if (callLog.sentiment === 'positive') { score += 10; reasons.push('Positive sentiment'); }
if ((callLog.duration_sec || 0) > 180) { score += 5; reasons.push('Long call (>3min)'); }

// Bonuses
if (lead.status === 'booked')      { score += 10; reasons.push('Meeting booked'); }
if ((lead.retry_count || 0) === 0) { score += 5;  reasons.push('Answered first call'); }

const finalScore = Math.min(score, 100);
const classification = finalScore >= 70 ? 'hot' : finalScore >= 40 ? 'warm' : 'cold';

return [{ json: { lead_id: lead.id, score: finalScore, classification, score_reasons: reasons, scored_at: new Date().toISOString() } }];
